mapper.select:
SELECT user_id as userId, username, real_name as realName, password, phone,
       email, avatar, gender, signature, address, status, create_time as createTime
FROM user
WHERE username = #{username}
   OR phone = #{username}
   OR email = #{username}

SELECT user_id as userId, username, real_name as realName, password, phone,
       email, avatar, gender, signature, address, status, create_time as createTime
FROM user WHERE phone = #{phone}

mapper.update:
UPDATE user
username = #{username}, password = #{password}, real_name = #{realName}, phone = #{phone}, email = #{email}, gender = #{gender}, signature = #{signature}, address = #{address}, avatar = #{avatar},
WHERE user_id = #{userId}

UPDATE follow
SET status = 0
WHERE follower_id = #{followerId} AND following_id = #{followingId}
